class Solution:
    def generateMatrix(self, n: int) -> List[List[int]]:
        m=[[0]*n for _ in range(n)]
        t,b,l,r,val=0,n-1,0,n-1,1
        while t<=b and l<=r:
            for c in range(l,r+1): m[t][c]=val; val+=1
            t+=1
            for i in range(t,b+1): m[i][r]=val; val+=1
            r-=1
            if t<=b:
                for c in range(r,l-1,-1): m[b][c]=val; val+=1
                b-=1
            if l<=r:
                for i in range(b,t-1,-1): m[i][l]=val; val+=1
                l+=1
        return m

